import { Link as MicrofrontendLink } from "@vercel/microfrontends/next/client";
import { ArrowRight } from "lucide-react";
import dynamic from "next/dynamic";

// Dynamically imported so the Radix accordion JS ships in a separate lazy chunk.
// The FAQ is below the fold — no need to block the critical path with
// @radix-ui/react-accordion + its shared primitives on initial load.
const FaqAccordion = dynamic<{ faqs: (typeof faqs)[number][] }>(() =>
  import("./faq-accordion").then((m) => ({ default: m.FaqAccordion })),
);

export const faqs = [
  {
    question: "What is Lightfast?",
    answer:
      "Lightfast is the superintelligence layer for founders. Built on a unified operating layer, it observes what's happening across your tools, remembers what happened, and gives agents and people a single system to reason and act through — without knowing which tools exist or how they work.",
  },
  {
    question: "What does 'operating layer' mean?",
    answer:
      "Think of Lightfast like an OS for your tool stack. Instead of agents making individual API calls to GitHub, Linear, Sentry, and Slack, they operate through Lightfast — express intent, get context, take action. One integration point for every tool, every team, every workflow.",
  },
  {
    question: "What tools do you integrate with?",
    answer:
      "Today we support GitHub (pushes, PRs, issues, reviews), Vercel (deployments, project activity), Sentry (errors, issues, alerts), and Linear (issues, comments, projects, cycles). Slack, Notion, Confluence, and PagerDuty are coming soon. Each integration ingests events automatically and continuously.",
  },
  {
    question: "How does the event system work?",
    answer:
      "Lightfast ingests structured events from your connected tools in real time. Every push, pull request, deployment, error, and issue becomes a normalized event you can subscribe to, filter, and act on. Events are immutable and causally ordered — facts your agents and workflows can rely on.",
  },
  {
    question: "How do agents and AI assistants use Lightfast?",
    answer:
      "Lightfast provides a REST API, TypeScript SDK, and MCP (Model Context Protocol) tools that any agent can use. Agents can search your workspace, get cited answers, find related context, and express intent that Lightfast resolves to the right tool and action. Same primitives for agents and people.",
  },
  {
    question: "What's coming after events?",
    answer:
      "Next is Memory — semantic search and cited answers across your entire tool stack. Everything from the event system gets indexed, connected, and made searchable by meaning. After that, full orchestration: agents express what they want in natural language, and Lightfast resolves it to the right tool, enforces your rules, and tracks everything.",
  },
  {
    question: "Is our data secure and private?",
    answer:
      "Every workspace is completely isolated — separate database schemas, separate vector namespaces, separate storage. Your data never mixes with others. We use industry-standard encryption at rest and in transit, and we never train on your data. You can delete your data anytime.",
  },
  {
    question: "How quickly can we get started?",
    answer:
      "Minutes. Connect your first source, and events start flowing immediately. Our TypeScript SDK installs with a single command, and MCP tools let AI assistants connect directly. No complex setup, no schema mapping, no custom pipelines.",
  },
  {
    question: "How does pricing work?",
    answer:
      "We offer a free Starter plan for up to 3 users with 2 sources. Team plan is $20/user/month with full event access and semantic search. Business plan includes unlimited sources and advanced features. Check our pricing page for full details.",
  },
];

export function FAQSection() {
  return (
    <div className="w-full">
      <div className="grid grid-cols-1 gap-8 lg:grid-cols-3 lg:gap-16">
        {/* Left: Badge */}
        <div>
          <span className="inline-flex h-7 items-center rounded-md border border-border px-3 text-muted-foreground text-sm">
            FAQ
          </span>
        </div>

        {/* Right: FAQ content - spans 2 columns */}
        <div className="lg:col-span-2">
          {/* Header with CTA */}
          <div className="mb-8 flex flex-col border-border border-b pb-8 lg:flex-row lg:items-start lg:justify-between">
            <div className="space-y-1">
              <p className="text-base text-muted-foreground leading-relaxed md:text-lg">
                Learn how Lightfast works.
              </p>
            </div>

            <div className="mt-6 lg:mt-0 lg:text-right">
              <p className="mb-2 text-muted-foreground text-sm">
                Ready to get started?
              </p>
              <MicrofrontendLink
                className="group inline-flex items-center gap-2 font-medium text-foreground text-sm transition-colors hover:text-muted-foreground"
                href="/early-access"
                prefetch={true}
              >
                Join early access
                <ArrowRight className="h-4 w-4 transition-transform group-hover:translate-x-0.5" />
              </MicrofrontendLink>
            </div>
          </div>

          {/* FAQ Accordion — client JS loaded lazily (below the fold) */}
          <FaqAccordion faqs={faqs} />
        </div>
      </div>
    </div>
  );
}

import { Icons } from "@repo/ui/components/icons";
import {
  Activity,
  ArrowUp,
  Briefcase,
  ChevronsUpDown,
  MessageSquare,
  Plug,
  Search,
  Settings,
} from "lucide-react";
import { ProductDemoMailbox } from "./product-demo-mailbox";

export function ProductDemo() {
  return (
    <div className="dark overflow-hidden rounded-lg">
      <div className="flex h-[540px] bg-background border overflow-hidden rounded-lg border-border/50 md:h-[580px] lg:h-[620px]">
        {/* Sidebar — hidden below lg */}
        <Sidebar />
        {/* Right column */}
        <div className="flex min-h-0 flex-1 flex-col pr-1.5 pb-1.5 md:pr-2 md:pb-2">
          {/* Inset card */}
          <div className="mt-1.5 flex flex-1 overflow-hidden rounded-lg border border-border/50 bg-background md:mt-2">
            <ProductDemoMailbox />
            <Chat />
          </div>
        </div>
      </div>
    </div>
  );
}

/* ------------------------------------------------------------------ */
/*  Sidebar                                                           */
/* ------------------------------------------------------------------ */

const sidebarPrimaryNav = [
  { label: "Explore", icon: MessageSquare, active: true },
];

const sidebarManageNav = [
  { label: "Events", icon: Activity },
  { label: "Sources", icon: Plug },
  { label: "Jobs", icon: Briefcase },
  { label: "Settings", icon: Settings },
];

function Sidebar() {
  return (
    <div className="hidden w-[14rem] shrink-0 flex-col lg:flex">
      {/* Header */}
      <div className="flex h-14 items-center gap-2 px-4">
        <Icons.logoShort className="size-3" />
        <span className="font-medium text-base font-pp">Lightfast</span>
        <button
          className="ml-auto flex size-6 items-center justify-center rounded-full text-muted-foreground hover:bg-muted"
          type="button"
        >
          <ChevronsUpDown className="size-3.5" />
        </button>
        <button
          className="flex size-6 items-center justify-center rounded-full text-muted-foreground hover:bg-muted"
          type="button"
        >
          <Search className="size-3.5" />
        </button>
      </div>

      {/* Primary nav */}
      <div className="flex flex-col gap-0.5 px-2">
        {sidebarPrimaryNav.map((item) => (
          <div
            className={`flex cursor-pointer items-center gap-2 rounded-xl px-2 py-1.5 text-sm transition-colors hover:bg-muted/50 hover:text-foreground ${
              item.active
                ? "bg-muted/50 font-medium text-foreground"
                : "text-muted-foreground"
            }`}
            key={item.label}
          >
            <item.icon className="size-3.5" />
            <span>{item.label}</span>
          </div>
        ))}
      </div>

      {/* Manage group */}
      <div className="mt-4 flex flex-col gap-0.5">
        <span className="px-4 text-muted-foreground text-xs">Manage</span>
        <div className="flex flex-col gap-0.5 px-2">
          {sidebarManageNav.map((item) => (
            <div
              className="flex cursor-pointer items-center gap-2 rounded-xl px-2 py-1.5 text-muted-foreground text-sm transition-colors hover:bg-muted/50 hover:text-foreground"
              key={item.label}
            >
              <item.icon className="size-3.5" />
              <span>{item.label}</span>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

/* ------------------------------------------------------------------ */
/*  Chat (empty state)                                                */
/* ------------------------------------------------------------------ */

function Chat() {
  return (
    <div className="flex flex-1 flex-col items-center justify-center bg-background">
      <div className="-mt-8 w-full max-w-3xl px-1.5 md:px-3 lg:px-6 xl:px-10">
        <p className="text-center font-semibold text-2xl">
          Explore your infrastructure
        </p>
        {/* Prompt input replica */}
        <div className="mt-4 w-full overflow-hidden rounded-xl border border-border/50 bg-card/40 shadow-sm backdrop-blur-md">
          <div className="flex flex-col">
            <div className="min-h-[32px] p-3 text-muted-foreground text-sm leading-6">
              Ask anything about your organization...
            </div>
          </div>
          <div className="flex items-center justify-end gap-2 p-2">
            <div className="flex size-8 items-center justify-center rounded-full border border-border/50 shadow-sm">
              <ArrowUp className="size-4" />
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

import { IntegrationLogoIcons } from "@repo/ui/integration-icons";
import { Search } from "lucide-react";

interface FeedEvent {
  detail: string;
  extra?: string[];
  label: string;
  source: "Vercel" | "GitHub" | "Sentry" | "Linear";
}

const FEED_EVENTS: FeedEvent[] = [
  {
    source: "GitHub",
    label: "PR Opened",
    detail: "#842 search index batching",
  },
  {
    source: "Sentry",
    label: "Issue Created",
    detail: "LF-1128 TypeError in worker",
    extra: [
      "TypeError: Cannot read property 'index' of undefined",
      "at SearchWorker.process (worker.ts:142)",
    ],
  },
  {
    source: "Linear",
    label: "Issue Updated",
    detail: "MEM-302 ranking threshold",
  },
  { source: "Vercel", label: "Deployment Ready", detail: "api@prod-us-east-1" },
  { source: "GitHub", label: "PR Merged", detail: "#839 edge cache warmup" },
  {
    source: "Sentry",
    label: "Metric Alert",
    detail: "p95 latency crossed 240ms",
    extra: [
      "Current: 312ms · Threshold: 240ms",
      "Region: us-east-1 · Window: 5m",
    ],
  },
];

const SOURCE_ICON_KEY: Record<
  FeedEvent["source"],
  keyof typeof IntegrationLogoIcons
> = {
  Vercel: "vercel",
  GitHub: "github",
  Sentry: "sentry",
  Linear: "linear",
};

export function ProductDemoMailbox() {
  return (
    <div className="flex w-[280px] shrink-0 flex-col border-border/40 border-r md:w-[300px] lg:w-[320px]">
      {/* Header */}
      <div className="flex items-center justify-between border-border/40 border-b px-3 py-2">
        <span className="font-medium text-sm">Events</span>
        <div className="flex items-center gap-1.5 text-muted-foreground text-xs">
          <span className="size-2 animate-pulse rounded-full bg-emerald-500" />
          Live
        </div>
      </div>

      {/* Search bar */}
      <div className="flex items-center gap-2 border-border/40 border-b px-3 py-2">
        <Search className="size-3.5 text-muted-foreground" />
        <span className="text-muted-foreground text-sm">Search...</span>
      </div>

      {/* Event rows */}
      <div className="flex-1 overflow-y-auto">
        {FEED_EVENTS.map((event, idx) => {
          const Icon = IntegrationLogoIcons[SOURCE_ICON_KEY[event.source]];
          return (
            <div
              className="flex cursor-pointer flex-col gap-2 border-border/40 border-b px-3 py-3 transition-colors hover:bg-muted/50"
              key={`${event.source}-${idx}`}
            >
              <div className="flex items-center gap-2">
                <Icon className="size-4 shrink-0 text-muted-foreground" />
                <span className="font-medium font-mono text-muted-foreground text-xs uppercase tracking-wide">
                  {event.source}
                </span>
              </div>
              <div className="flex items-center gap-2 overflow-hidden text-sm">
                <span className="shrink-0 text-foreground">{event.label}</span>
                <span className="shrink-0 text-muted-foreground/40">·</span>
                <span className="truncate text-muted-foreground">
                  {event.detail}
                </span>
              </div>
              {event.extra && (
                <div className="flex flex-col gap-1 border-border/50 border-t pt-2">
                  {event.extra.map((line, lineIndex) => (
                    <span
                      className="truncate font-mono text-muted-foreground/50 text-xs leading-tight"
                      key={`${lineIndex}-${line}`}
                    >
                      {line}
                    </span>
                  ))}
                </div>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
}

